import * as React from 'react';

import { CloseIcon, SearchIcon } from '../icons';
import { Input } from '../input';
import { cn } from '../utils/cn';

type SearchInputProps = React.ComponentProps<'input'> & {
  onClear?: () => void;
};

/**
 * A text input with a leading search icon and an optional trailing clear button.
 *
 * Composed from `Input` and icon components.
 */
function SearchInput({
  className,
  value,
  onClear,
  ...props
}: SearchInputProps) {
  const showClear = value !== undefined && value !== '' && onClear;

  return (
    <div data-slot="search-input" className={cn('relative', className)}>
      <span className="pointer-events-none absolute inset-y-0 left-0 flex items-center pl-2.5 text-muted-foreground">
        <SearchIcon size="sm" />
      </span>
      <Input
        type="text"
        value={value}
        className={cn('pl-9', showClear && 'pr-9')}
        {...props}
      />
      {showClear && (
        <button
          type="button"
          data-slot="search-input-clear"
          onClick={onClear}
          aria-label="Clear search"
          className="absolute inset-y-0 right-0 flex items-center pr-2.5 text-muted-foreground hover:text-foreground"
        >
          <CloseIcon size="sm" />
        </button>
      )}
    </div>
  );
}

export { SearchInput };
export type { SearchInputProps };
